-- Bundle: agent-tools/exports/stage3_ingestion_bundle_34-36m.json

BEGIN;

CREATE TABLE IF NOT EXISTS public.pl_stage3_picks (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  age_band_id TEXT NOT NULL REFERENCES public.pl_age_bands(id) ON DELETE RESTRICT,
  category_type_id UUID NOT NULL REFERENCES public.pl_category_types(id) ON DELETE CASCADE,
  source_category_entity_id TEXT NOT NULL,
  pick_rank INTEGER NOT NULL CHECK (pick_rank > 0),
  longlist_rank INTEGER NOT NULL CHECK (longlist_rank > 0),
  status TEXT NOT NULL CHECK (status IN ('visible', 'backup', 'skip')),
  is_visible BOOLEAN NOT NULL DEFAULT true,
  is_locked BOOLEAN NOT NULL DEFAULT true,
  best_for_tag TEXT,
  product_name TEXT NOT NULL,
  brand TEXT,
  retailer TEXT,
  product_url TEXT,
  image_url TEXT,
  price_text TEXT,
  stock_status TEXT,
  age_mark_on_listing TEXT,
  product_description TEXT,
  ember_verdict TEXT,
  why_it_fits TEXT,
  caveats TEXT,
  buy_borrow_hold_off TEXT,
  gift_suitable BOOLEAN,
  gift_note TEXT,
  ownership_note TEXT,
  safety_notes TEXT,
  evidence_tier TEXT,
  evidence_sources TEXT[],
  founder_qa_flag TEXT,
  research_payload JSONB NOT NULL DEFAULT '{}'::jsonb,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  CONSTRAINT pl_stage3_picks_unique UNIQUE (age_band_id, category_type_id, pick_rank, status)
);

ALTER TABLE public.pl_stage3_picks ENABLE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "pl_stage3_picks_public_read" ON public.pl_stage3_picks;
CREATE POLICY "pl_stage3_picks_public_read" ON public.pl_stage3_picks
  FOR SELECT
  TO anon, authenticated
  USING (
    status = 'visible'
    AND is_visible = true
    AND (
      is_locked = false
      OR lower(coalesce(auth.jwt() ->> 'email', '')) = 'timwd23@gmail.com'
      OR lower(coalesce(auth.jwt() -> 'app_metadata' ->> 'membership_type', '')) = 'ember_plus'
    )
  );

DROP POLICY IF EXISTS "pl_stage3_picks_admin_all" ON public.pl_stage3_picks;
CREATE POLICY "pl_stage3_picks_admin_all" ON public.pl_stage3_picks
  FOR ALL
  USING (public.is_admin())
  WITH CHECK (public.is_admin());

GRANT SELECT ON public.pl_stage3_picks TO anon, authenticated;

CREATE INDEX IF NOT EXISTS pl_stage3_picks_age_category_rank_idx
  ON public.pl_stage3_picks(age_band_id, category_type_id, status, pick_rank);

DROP TRIGGER IF EXISTS trg_pl_stage3_picks_updated_at ON public.pl_stage3_picks;
CREATE TRIGGER trg_pl_stage3_picks_updated_at
  BEFORE UPDATE ON public.pl_stage3_picks
  FOR EACH ROW
  EXECUTE FUNCTION public.set_updated_at();

DROP VIEW IF EXISTS public.v_gateway_stage3_picks_public;
CREATE VIEW public.v_gateway_stage3_picks_public
WITH (security_invoker = true) AS
SELECT
  s.id,
  s.age_band_id,
  s.category_type_id,
  ct.slug AS category_type_slug,
  s.source_category_entity_id,
  s.pick_rank,
  s.longlist_rank,
  s.status,
  s.is_visible,
  s.is_locked,
  s.best_for_tag,
  s.product_name,
  s.brand,
  s.retailer,
  s.product_url,
  s.image_url,
  s.price_text,
  s.stock_status,
  s.age_mark_on_listing,
  s.product_description,
  s.ember_verdict,
  s.why_it_fits,
  s.caveats,
  s.buy_borrow_hold_off,
  s.gift_suitable,
  s.gift_note,
  s.ownership_note,
  s.safety_notes,
  s.evidence_tier,
  s.evidence_sources,
  s.founder_qa_flag,
  s.research_payload
FROM public.pl_stage3_picks s
JOIN public.pl_category_types ct ON ct.id = s.category_type_id
WHERE s.status = 'visible'
  AND s.is_visible = true
  AND s.is_locked = false;

GRANT SELECT ON public.v_gateway_stage3_picks_public TO anon, authenticated;

DELETE FROM public.pl_stage3_picks
WHERE age_band_id = '34-36m'
  AND source_category_entity_id IN ('cat_balance_stepping_stones', 'cat_feelings_faces_books', 'cat_jigsaw_puzzles', 'cat_picture_story_books', 'cat_small_world_figures', 'cat_threading_beads', 'cat_visual_routine_cards');

WITH stage3_rows AS (
  SELECT *
  FROM (VALUES
    ('cat_balance_stepping_stones', 1, 1, 'visible', true, false, 'Best for rule-based paths', 'Gonge River Stones (set of 6)', 'Gonge', 'Liberty House Toys', 'https://www.libertyhousetoys.com/gonge-river-stones', NULL, '£55.00', 'in_stock', 'Ages 2-99 years (Liberty House Toys product page)', 'Six stackable triangular stepping stones in two sizes. Each stone has three slope sides so you can dial difficulty when laying a path.', 'When cushions-and-tape has run its course, this is the proper path kit. Lay step–pause–turn rules on laminate without daredevil height. Each stone’s three sides progress difficulty without buying more. Pricey — borrow from nursery or try pre-loved before committing.', 'Variable steepness and two sizes create sequenced, rule-based paths — the core 34–36m shift versus earlier throw-and-aim games.', 'Premium price; one set may feel short for long corridors — extend with tape markers rather than duplicating the same set.', 'buy', true, 'Strong gift if the family has floor space and already plays active indoor games. Pair with a simple rule card.', 'Many nurseries own these — ask before duplicating. Common on pre-loved sites.', 'Non-slip rubber base. Supervise on hard floors until your child knows their limits — planned movement, not height daredevil play.', 'strong', ARRAY['https://www.libertyhousetoys.com/gonge-river-stones', 'https://www.amazon.co.uk/Gonge-1137385-River-Stones/dp/B000ANIVRG']::text[], 'check_price'),
    ('cat_balance_stepping_stones', 2, 2, 'visible', true, true, 'Best for tight budgets', 'Tippi Sensory Stepping Stones (5-pack)', 'Tippi', 'Amazon UK', 'https://www.amazon.co.uk/Tippi-Sensory-Stepping-Stones-Kids/dp/B0FCSQ9WKX', NULL, '£15.99', 'in_stock', 'Balance toys for children age 18 months + (Amazon UK listing title/spec)', 'Five stackable stepping stones with textured tops and rubber bases. Low profile for indoor lava-game paths on a budget.', 'If tape lines work but you want proper stones without Gonge money, this is the sensible starter. Textured tops give sensory feedback for cautious steppers. Lower and flatter than premium kit — fine for step-and-turn rules, less for big jumps. Replaces National Geographic here because pure 3+ marks fail FF for 34-month-olds in this band.', '18 months+ mark overlaps 34–36m; five pieces enough for a hallway path with pause points at nearly three.', 'Amazon UK review widget bot-blocked to agents — founder should sanity-check recent ratings on click. Less height progression than Gonge.', 'buy', true, 'Easy-wrap budget gift for families testing whether path play sticks.', 'Generic stepping-stone shape — many families already own a similar set.', 'Rubber bases for laminate; low fall height. Supervise first sessions.', 'specialist', ARRAY['https://www.amazon.co.uk/Tippi-Sensory-Stepping-Stones-Kids/dp/B0FCSQ9WKX']::text[], 'confirm_reviews_on_human_click'),
    ('cat_balance_stepping_stones', 3, 3, 'visible', true, true, 'Best for small spaces', 'Edx Education Step-A-Stumps (set of 6)', 'Edx Education', 'The Dyslexia Shop', 'https://www.thedyslexiashop.co.uk/products/step-a-stumps-6-piece-modular-balance-stepping-stones-for-sensory-play', NULL, '£87.99', 'in_stock', 'From 18 months upwards (The Dyslexia Shop listing copy)', 'Six ribbed, nesting stump stepping stones in three sizes, with a carry bag. Textured tops give sensory feedback under bare feet.', 'When storage is tight but you want more than flat stones, these nest into one stack with a carry bag. Ribbed tops suit children who pause to feel the surface before stepping. Good for step-and-pause paths; less exciting for big jumps.', 'Compact nesting plus three size grades supports progressive path difficulty in small rooms without cluttering the flat.', 'Premium price for plastic; Shopedx lists £105.60 — shop around before buying.', 'buy', true, 'Better gift for families who value tidy storage and sensory texture over brand recognition.', 'Common in nurseries — check before gifting duplicates.', 'Rubber-edged bases; ribbed tops reduce slip. Supervise first sessions on hard floors.', 'specialist', ARRAY['https://www.thedyslexiashop.co.uk/products/step-a-stumps-6-piece-modular-balance-stepping-stones-for-sensory-play', 'https://www.shopedx.co.uk/products/step-a-stumps']::text[], 'check_price'),
    ('cat_balance_stepping_stones', 4, 4, 'visible', true, true, 'Best for height practice', 'Gonge Hilltops (set of 3)', 'Gonge', 'Liberty House Toys', 'https://www.libertyhousetoys.com/gonge-hilltops', NULL, '£74.99', 'in_stock', 'Ages 2+ years (Liberty House Toys)', 'Three stackable hilltop platforms at different fixed heights. Non-slip feet; designed not to tip when stepped on carefully.', 'Pick when the shift is step-up, pause on the tall one, turn, step down — height sequencing rather than flat hopping. Combine with River Stones for a mixed path. Hands nearby until confident; this brief is planned movement, not bouncing thrills.', 'Three fixed heights teach planned up-down movement — distinct from flat stones and from 31–33m throw games.', 'Only three pieces — short path unless combined with cushions or River Stones. Liberty House public review count is thin.', 'buy', true, 'Impressive for active families with cleared floor space. Best after flat stones.', 'Pairs with River Stones — check whether family already owns Gonge before doubling up.', 'Non-slip rubber feet; anti-overturn design. Supervise height steps until your child can pause without hands.', 'specialist', ARRAY['https://www.libertyhousetoys.com/gonge-hilltops', 'https://www.gonge.com/products/hilltops-nordic']::text[], 'check_age_fit'),
    ('cat_balance_stepping_stones', 5, 5, 'visible', true, true, 'Best for straight paths', 'Edx Education Step-A-Trails (set of 6)', 'Edx Education', 'Shopedx', 'https://www.shopedx.co.uk/products/step-a-trails', NULL, '£96.00', 'in_stock', 'Age: 18 months+ (Shopedx product page)', 'Six low balance-beam sections that link into straight or curved walking paths. Ribbed tops; six centimetres high — walk the line, not hop.', 'This is the path half of the category. Lay a walking line down the hall: heel-toe, pause at the end, turn, come back. Lower than stones so it suits cautious nearly-threes who need rule-based walking before jumping.', 'Beam paths train planned step-and-pause movement without jump height — distinct product type from all stone picks.', 'Expensive for six plastic beams; needs a cleared hallway run.', 'buy', true, 'Niche gift — best when parents want active indoor play and have space for a floor path.', 'Tape on floor may suffice — only buy if child has outgrown tape and wants a raised edge.', 'Low 6.4 cm height limits fall risk. Ensure sections sit flat on hard floors.', 'specialist', ARRAY['https://www.shopedx.co.uk/products/step-a-trails', 'https://www.nappaawards.com/product/step-a-trails/']::text[], 'check_price'),
    ('cat_feelings_faces_books', 1, 1, 'visible', true, false, 'Best for three-way wobbles', 'On Sudden Hill', 'Linda Sarah & Benji Davies', 'LoveReading4Kids', 'https://www.lovereading4kids.co.uk/book/9781471119293/isbn/On-Sudden-Hill-by-Linda-Sarah.html', NULL, '£7.19', 'in_stock', 'Scholastic UK: Suitable for 3–6 years', 'Two box-play best friends bristle when Shu wants to join their cardboard adventures on Sudden Hill.', 'Friend play is getting messier now — a third child can feel like being pushed out. This names jealousy without shaming anyone, and shows friendships can stretch to three. Borrow from the library first; it turns up in nurseries a lot.', 'Models three-way friendship tension, exclusion and repair — the core 34–36m shift beyond emotion labelling.', 'LoveReading lists “5+ readers” as a reading level — Scholastic’s 3–6 shelf mark is the age signal used here.', 'borrow', true, 'Warm after a messy playdate — not a lecture.', 'Borrow first — common in nurseries and hand-me-down boxes.', NULL, 'strong', ARRAY['https://shop.scholastic.co.uk/products/On-Sudden-Hill-Linda-Sarah-9781471119293', 'https://www.lovereading4kids.co.uk/book/9781471119293/isbn/On-Sudden-Hill-by-Linda-Sarah.html']::text[], 'check_price'),
    ('cat_feelings_faces_books', 2, 2, 'visible', true, true, 'Best for jealous moments', 'Pip and Posy: The New Friend', 'Camilla Reid & Axel Scheffler', 'Amazon UK', 'https://www.amazon.co.uk/dp/0857638742', NULL, '£7.99', 'in_stock', 'Nosy Crow series age band: Ages 2–5', 'At the beach, Posy wakes to find Pip playing with new friend Zac — jealousy, then a small kind act reunites them.', 'Not another feelings chart — this is the moment your child watches their best friend laugh with someone else. Posy fixes it herself, which gives you language for real playgroup wobbles. Borrow if you already own other Pip & Posy titles.', 'Shows jealousy, inclusion and repair in peer play without adult rescue — distinct from 31–33m worry-retelling books.', 'Paperback is the value pick; board book ISBN differs.', 'borrow', true, 'Warm story gift after a playdate bust-up.', 'High duplication risk — check the shelf and nursery bag first.', NULL, 'strong', ARRAY['https://nosycrow.com/book/pip-and-posy-the-new-friend/', 'https://www.amazon.co.uk/dp/0857638742']::text[], 'check_price'),
    ('cat_feelings_faces_books', 3, 3, 'visible', true, true, 'Best for grudge loops', 'The Sour Grape', 'Jory John & Pete Oswald', 'Scholastic UK', 'https://shop.scholastic.co.uk/products/Sour-Grape-9780063283800', NULL, '£5.49', 'in_stock', 'Scholastic UK: Suitable for 3–5 years', 'A grape who stockpiles grudges learns forgiveness after realising a birthday mix-up — and how sour holding on feels.', 'When friend play goes wrong, nearly-threes can stay cross long after the toy is back. This is funny enough for repeat reads and gives you a light way into sorry and moving on. Library copy is fine if you already own The Good Egg.', 'Forgiveness and fairness in friendships — social repair, not basic emotion naming.', 'Some wordplay lands above toddler level; the visual story carries it.', 'borrow', true, 'Funny enough to re-read after a squabble.', 'Food Group series is widely owned — borrow before buying another.', NULL, 'strong', ARRAY['https://shop.scholastic.co.uk/products/Sour-Grape-9780063283800', 'https://www.lovereading4kids.co.uk/book/9780063283800/isbn/The-Sour-Grape-by-Jory-John.html']::text[], 'check_price'),
    ('cat_feelings_faces_books', 4, 4, 'visible', true, true, 'Best for sharing rows', 'Can You Share, Little Whale?', 'Jonny Lambert', 'Little Tiger', 'https://littletiger.co.uk/product/can-you-share-little-whale-2', NULL, '£7.99', 'in_stock', 'Publisher Age Range: 3–7 years', 'Little Whale hates sharing the pod, snacks and Mum’s attention until friend Blue models what sharing looks like.', 'Fresh 2024 pick for the tug-of-war over the good toy or the front of the queue. Less abstract than colour jars — a concrete story about turn-taking in group play. Worth buying if your library hold queue is long.', 'Sharing and attention jealousy in peer contexts — matches turn-taking cluster without repeating 28–30m emotion-label books.', 'Newer title — fewer reviews than classics; strong editorial comparables.', 'buy', true, 'Good gift if they do not already own three sharing books.', 'Lower duplication risk than Pip & Posy — fewer households own it yet.', NULL, 'good', ARRAY['https://littletiger.co.uk/product/can-you-share-little-whale-2', 'https://www.motherandbaby.com/reviews/toddler-toys/the-best-books-for-teaching-children-to-share/']::text[], 'check_price'),
    ('cat_feelings_faces_books', 5, 5, 'visible', true, true, 'Best for mine fights', 'That''s (Not) Mine', 'Anna Kang & Christopher Weyant', 'Hachette UK', 'https://www.hachette.co.uk/titles/anna-kang/thats-not-mine/9781444923339/', NULL, '£6.99', 'in_stock', 'Publisher recommended ages 2–7', 'Two furry friends battle over one chair, shouting “It’s mine!” until they choose to play together instead.', 'The “that’s MINE” phase meets friend play. Short, shouty text mirrors real arguments, then pivots to shared play — handy after playdates where nobody wanted to swap. Borrow if you already have two sharing books on the go.', 'Turn-taking and territory fights between peers — practical social rules, not naming happy/sad.', 'Hachette product page highlights ebook ISBN; paperback edition cross-checked via publisher age data.', 'borrow', true, 'Funny enough to gift to a family without a big picture-book shelf.', 'Borrow-first — overlaps with other sharing titles many nurseries already stock.', NULL, 'strong', ARRAY['https://www.hachette.co.uk/titles/anna-kang/thats-not-mine/9781444923339/', 'https://www.motherandbaby.com/reviews/toddler-toys/the-best-books-for-teaching-children-to-share/']::text[], 'check_price'),
    ('cat_jigsaw_puzzles', 1, 1, 'visible', true, false, 'Best for first 12-piece plan', 'First Farm Friends Jigsaw Puzzles', 'Orchard Toys', 'Amazon UK', 'https://www.amazon.co.uk/Orchard-Toys-292-Friends-Puzzles/dp/B08R6BWGX1', NULL, '£7.92', 'in_stock', 'Age 2+', 'Two chunky 12-piece farm jigsaws in one box. Wipe-clean cardboard pieces with bold background colours so the picture stays visible while they work.', 'This is the step up from peg posting: real interlocking pieces, but the pig and cow scenes stay readable while they turn and compare. Strong visual clues keep frustration low — a solid third-birthday gift if peg puzzles are already easy.', '12 pieces hits the strategy brief without jumping to 20+; UK-made Orchard quality; clear picture-first design; strong Amazon and brand-site proof.', 'Age mark says 2+ — honest for nearly three, not a fresh 18m buy. Start with one puzzle out; save the second for a win later in the week.', 'buy', true, 'Reliable small-box gift under £10; wrap-friendly and familiar on UK nursery shelves.', 'Skip if you already own Orchard 12-piece farm or jungle sets from a younger sibling — borrow a different theme first.', 'Small parts — supervise if mouthing is still common at the younger end of nearly three.', 'strong', ARRAY['Amazon UK B08R6BWGX1', 'orchardtoys.com First Farm Friends']::text[], 'none'),
    ('cat_jigsaw_puzzles', 2, 2, 'visible', true, true, 'Best for jungle theme fans', 'First Jungle Friends Jigsaw Puzzles', 'Orchard Toys', 'Orchard Toys', 'https://www.orchardtoys.com/buy/first-jungle-friends-jigsaw-puzzles_496.htm', NULL, '£8.50', 'in_stock', 'Age 2+', 'Two chunky 12-piece jungle jigsaws in one box. Wipe-clean pieces with bold animals and background colours to guide turning and matching.', 'Same 12-piece step-up as Farm Friends but with monkey and giraffe scenes — pick this if farm animals are already everywhere at nursery. If peg puzzles are still easy, this is the proper interlocking upgrade.', 'Identical Orchard First Friends quality with a distinct theme for children bored of farm sets.', 'Near-duplicate of rank 1 — own one theme, not both, unless gifting to a different household.', 'buy', true, 'Strong unisex gift when you know they do not already have Farm Friends.', 'Borrow or buy jungle only if farm 12-piece sets are already in the cupboard.', 'Small parts possible — standard toddler puzzle supervision.', 'specialist', ARRAY['orchardtoys.com First Jungle Friends', 'argosytoys.co.uk EAN 5011863001863']::text[], 'confirm_reviews_on_human_click'),
    ('cat_jigsaw_puzzles', 3, 3, 'visible', true, true, 'Best for warm-up sessions', 'On The Farm — My First Jigsaw Puzzles', 'Ravensburger', 'Amazon UK', 'https://www.amazon.co.uk/Ravensburger-First-Puzzle-Jigsaw-Puzzles/dp/B008IZHSEA', NULL, '£5.82', 'in_stock', '18 months+', 'Four farm mini-jigsaws in one box — two, three, four and five pieces. Extra-thick Ravensburger cardboard with bold animal pictures.', 'Box says 18m+ but at nearly three you want the four- and five-piece puzzles, not the two-piece warm-ups. Thick pieces survive repeated turning — low-stakes practice before a 12-piece Orchard.', 'Excellent cardboard quality; huge Amazon review base; teaches strategy on 4–5 pieces before scaling up.', '18m box mark fails freshness if marketed as a new-stage buy — position as use the top two puzzles only. Two-piece puzzles are too easy for most 34–36m children.', 'buy', true, 'Cheap, recognisable brand — fine as a stocking filler if they have no jigsaws yet.', 'If peg puzzles and 2-piece sets are mastered, start on the 4–5 piece puzzles or skip to rank 1.', 'Standard small-parts guidance for youngest marked age.', 'strong', ARRAY['Amazon UK B008IZHSEA', 'In The Playroom review', 'Mum of a Premature Baby review']::text[], 'check_age_fit'),
    ('cat_jigsaw_puzzles', 4, 4, 'visible', true, true, 'Best for wooden durability', 'Safari — 6 Piece Puzzles (3 puzzles)', 'Bigjigs Toys', 'Wooden Toy Shop', 'https://www.woodentoyshop.co.uk/products/safari-6-piece-puzzles-3-puzzles', NULL, '£5.99', 'in_stock', 'Age 2+', 'Three wooden safari jigsaws, six pieces each, in separate trays. Chunky FSC wood pieces with bold scene pictures.', 'For parents who want something that survives being stepped on. Six pieces needs a small plan, but the trays keep the picture visible. Good counterpoint to cardboard if you already own Orchard farm sets.', 'Real interlocking wood at 6 pieces; UK heritage brand; budget price; distinct from cardboard picks.', 'Smaller completed size than Orchard 12-piece — less floor presence. Fewer aggregated online reviews than Amazon bestsellers.', 'buy', true, 'Compact wooden set — nice for families avoiding plastic; under £6.', 'Also available as Big Movers (vehicles) if safari animals are duplicated at home.', 'Conforms to current European safety standards per manufacturer.', 'specialist', ARRAY['woodentoyshop.co.uk BJ818', 'Amazon UK B00HWHNNRG', 'bigjigstoys.co.uk Safari 6-piece']::text[], 'confirm_reviews_on_human_click'),
    ('cat_jigsaw_puzzles', 5, 5, 'visible', true, true, 'Best for vehicle quick wins', 'Rescue Squad Jigsaw Puzzle', 'Orchard Toys', 'Amazon UK', 'https://www.amazon.co.uk/Orchard-Toys-Rescue-Squad-Jigsaw/dp/B0007TXTJS', NULL, '£6.50', 'in_stock', 'Age 2+', 'Six emergency-vehicle jigsaws in one box — two-piece and three-piece puzzles — plus six character play pieces for matching play.', 'Brilliant confidence builder before 12-piece sets: turn a piece, compare the picture, try again — without a table full of parts. Vehicle-mad nearly-threes will line up drivers beside toy fire engines.', 'Real interlocking pieces at 2–3 count; huge Amazon review base; distinct emergency-vehicle hook.', 'May feel easy within weeks for confident puzzlers — move to rank 1 when they ask for more pieces. Bag small play pieces if mouthing persists.', 'buy', true, 'Compact box under £7; strong for children who love sirens and rescue vehicles.', 'Different enough from farm/jungle 12-piece sets to own alongside — unless you already have Orchard transport first-puzzles.', 'Small play pieces — bag for younger nearly-threes still mouthing.', 'strong', ARRAY['Amazon UK B0007TXTJS', 'orchardtoys.com Rescue Squad']::text[], 'none'),
    ('cat_picture_story_books', 1, 1, 'visible', true, false, 'Best for open choices', 'You Choose', 'Pippa Goodhart & Nick Sharratt', 'Penguin UK', 'https://www.penguin.co.uk/books/305040/you-choose-by-goodhart-pippa/9780141379319', NULL, '£7.99', 'in_stock', 'BookTrust interest age 3-7 years', 'Picture book where the child picks a face, a house, an outfit and a pet on every spread, then explains the choice.', 'This is still the cleanest fit when your nearly-three wants to pick and explain on every page. If a nursery or grandparent copy is already doing the rounds, borrow it first — buy only once you know it isn''t already on the shelf.', 'Choice-led pages are built for what-next and why talk — the category benchmark for nearly-three talk-back.', 'Very widely owned across UK families — check the shelf and nursery book box before buying new.', 'borrow', true, 'Only gift if you know they do not already have a copy — ask first.', 'Borrow or bring back out — many nurseries and grandparents already own this.', NULL, 'strong', ARRAY['https://www.booktrust.org.uk/book-recommendations/bookfinder/you-choose/', 'https://www.penguin.co.uk/books/305040/you-choose-by-goodhart-pippa/9780141379319']::text[], 'check_price'),
    ('cat_picture_story_books', 2, 2, 'visible', true, true, 'Best for saying no', 'Don''t Let the Pigeon Drive the Bus! (board book)', 'Mo Willems', 'Amazon UK', 'https://www.amazon.co.uk/dp/1406386073', NULL, '£6.99', 'in_stock', 'Walker board edition: Ages 1-5', 'Comic board book where a pleading pigeon repeatedly asks the reader to let him drive the bus, and the child must answer.', 'Every spread gives your child a job: say no, explain why, and hold their ground when the pigeon argues back. It''s less choice-led than You Choose, but brilliant when they want to talk back with confidence rather than just pick an option.', 'Call-and-response dialogue lets the child lead the conversation — active talk-back rather than passive listening.', 'High-energy read — not the calmest bedtime pick if your child is already wound up.', 'borrow', true, 'Fun gift for a child who likes being in on the joke — check they don''t already own the paperback.', 'Popular classic — borrow first if the family already has other Mo Willems titles.', NULL, 'strong', ARRAY['https://www.waterstones.com/book/dont-let-the-pigeon-drive-the-bus/mo-willems/9781406386073', 'https://www.walker.co.uk/9781406386073/dont-let-the-pigeon-drive-the-bus/']::text[], 'check_price'),
    ('cat_picture_story_books', 3, 3, 'visible', true, true, 'Best for guessing what''s next', 'Oh No, George! (board book)', 'Chris Haughton', 'Amazon UK', 'https://www.amazon.co.uk/dp/140635791X', NULL, '£6.99', 'in_stock', 'Walker board edition: Ages 1-5', 'George the dog wants to be good but keeps giving in to temptation — the reader is asked what he should do and what happens next.', 'George keeps asking your child what he should do next, and whether he''ll get it wrong again — a proper prediction loop, not a one-off question. Good for a child who likes calling out the answer before you turn the page.', 'The repeated will-he-won''t-he beat keeps talk-back going page after page — prediction plus explanation, not passive narration.', 'Board edition review count is thinner than the mega-sellers in this list — still comfortably above the review bar.', 'borrow', true, 'Nice gift alongside another Haughton title if the family collects the set.', 'Less universally owned than You Choose or Pigeon — lower duplication risk.', NULL, 'good', ARRAY['https://www.waterstones.com/book/oh-no-george/chris-haughton/9781406357912', 'https://uk.bookshop.org/p/books/oh-no-george-a-hilarious-read-aloud-classic-about-a-dog-trying-his-best-to-be-good-the-perfect-gift-for-tickling-funny-bones-chris-haughton/f94edd4d32692e2b?ean=9781406357912']::text[], 'check_price'),
    ('cat_picture_story_books', 4, 4, 'visible', true, true, 'Best for predicting plans', 'Shh! We Have a Plan (board book)', 'Chris Haughton', 'Amazon UK', 'https://www.amazon.co.uk/dp/1406361658', NULL, '£6.99', 'in_stock', 'Walker board edition: Ages 1-5', 'Four friends creep through the woods with a hushed plan to catch a bird, while one friend keeps getting it wrong.', 'Your child has to work out whether the plan will actually work, and explain what went wrong when it doesn''t. Quieter than Pigeon or George, so it''s a better fit for a calmer chat rather than a giggly one.', 'The hushed, repeated plan-then-mishap structure asks the child to predict outcomes and explain what went wrong — talk-back without the noise of Pigeon or George.', 'Board edition review count is modest — comfortably above the review bar but thinner than the household-name picks.', 'borrow', true, 'Works well as part of a small Chris Haughton set gift.', 'Lower duplication risk than You Choose or Pigeon.', NULL, 'good', ARRAY['https://www.waterstones.com/book/shh-we-have-a-plan/chris-haughton/9781406361650', 'https://www.walker.co.uk/9781406361650/shh-we-have-a-plan/']::text[], 'check_price'),
    ('cat_picture_story_books', 5, 5, 'visible', true, true, 'Best for is-it-a-shark guesses', 'Shark in the Park', 'Nick Sharratt', 'Penguin UK', 'https://www.penguin.co.uk/books/327168/shark-in-the-park-by-sharratt-nick/9780552549776', NULL, '£6.99', 'in_stock', 'Publisher shelf mark: Ages 2-5', 'Timmy looks through his telescope in the park and repeatedly wonders ''is it a shark?'' — the reader answers each time.', 'The lightest, most repeatable pick on this list — perfect for a tired evening when the other four feel too talky. Your child answers the same question in a new way each time, which is a gentle entry point into talk-back rather than the deepest one.', 'The repeated is-it-a-shark question is simpler than the Top 4''s choice or plan-led formats, but still asks the child to look, guess and explain what they see.', 'Less explanation-heavy than the rest of the Top 5 — a good warm-up, not the main event, for a chatty nearly-three.', 'borrow', true, 'Good small gift alongside a bigger present — check the shelf for other Sharratt titles first.', 'Popular Sharratt classic — borrow first if the family already owns other titles by the same illustrator.', NULL, 'strong', ARRAY['https://www.penguin.co.uk/books/327168/shark-in-the-park-by-sharratt-nick/9780552549776', 'https://www.nicksharratt.com/books/shark-in-the-park']::text[], 'check_price'),
    ('cat_small_world_figures', 1, 1, 'visible', true, false, 'Best for get-on go return', 'Happyland London Bus Playset', 'Early Learning Centre / Happyland', 'Moonpig (TEAL / The Entertainer)', 'https://www.moonpig.com/uk/gifts/p/happyland-london-bus-playset/teal-549251/', NULL, '£25.00', 'in_stock', 'Suitable for age 12 months + (Moonpig); ELC / Entertainer also list Ages 2-5', 'Chunky red London bus with three figures and a stop — lift the deck, seat passengers, drive, and store them back inside.', 'This is still the cleanest get-on / go / return scene for a nearly-three who already narrates trips. If a Happyland bus is already in the cupboard or at nursery, bring it back out before buying another.', 'Bus + stop + people make a whole mini story without tiny classic-Playmobil parts.', 'Very widely owned in UK homes — high duplication risk. Batteries for sounds.', 'borrow', true, 'Only gift if you know they do not already have a Happyland bus.', 'Borrow or bring back out — Happyland buses turn up in hand-me-downs and nurseries.', NULL, 'specialist', ARRAY['https://www.moonpig.com/uk/gifts/p/happyland-london-bus-playset/teal-549251/', 'https://www.thetoyshop.com/shop-by-age/2-3-years/Happyland-London-Bus-Playset/p/549251']::text[], 'confirm_reviews_on_human_click'),
    ('cat_small_world_figures', 2, 2, 'visible', true, true, 'Best for airport board and go', 'PLAYMOBIL Junior Airport Shuttle Bus (71689)', 'Playmobil Junior', 'Playmobil UK', 'https://www.playmobil.com/en-gb/junior:-airport-shuttle-bus/71689.html', NULL, 'Confirm on Playmobil till', 'in_stock', 'Junior Ages 1-4 years', 'Junior airport shuttle with figures to board, drive and drop off — a travel story without retired DUPLO sets.', 'Use this when the trip is airport or holiday travel rather than a red London bus. Still Junior only — and the Playmobil page is buyable today, unlike the retired DUPLO Bus Ride.', 'Board, go, arrive — whole-scene travel on Junior age marks with chunky people.', 'Brand page does not expose scrapeable UK review counts — specialist exemption.', 'buy', true, 'Good gift for travel-obsessed nearly-threes who already have a Happyland bus.', 'Lower duplication than Happyland; pairs well with #1 rather than replacing it.', NULL, 'specialist', ARRAY['https://www.playmobil.com/en-gb/junior:-airport-shuttle-bus/71689.html']::text[], 'confirm_price_and_reviews'),
    ('cat_small_world_figures', 3, 3, 'visible', true, true, 'Best for help-and-rescue roles', 'PLAYMOBIL Junior Everyday Heroes (71692)', 'Playmobil Junior', 'Playmobil UK', 'https://www.playmobil.com/en-gb/junior:-everyday-heroes/71692.html', NULL, '£27.99 (third-party list; confirm on Playmobil till)', 'in_stock', 'Age: 1 years and up / Junior 1-4 years', 'Junior-scale doctor, firefighter and police play with chunky vehicles so the child can act help, go and return.', 'Use this when the story is help — someone needs the doctor, fire engine or police — not just another bus ride. Stick to Junior; classic Playmobil is the wrong age mark for this band.', 'Help roles give feelings and places to the pretend scene beyond travel alone.', 'Brand page does not expose a scrapeable UK review count — specialist exemption.', 'buy', true, 'Strong gift if the child already talks about helpers; avoid if classic Playmobil (3+) is what was requested.', 'Less ubiquitous than Happyland buses — lower duplication risk.', NULL, 'specialist', ARRAY['https://www.playmobil.com/en-gb/junior:-everyday-heroes/71692.html']::text[], 'confirm_price_and_reviews'),
    ('cat_small_world_figures', 4, 4, 'visible', true, true, 'Best for load tip return', 'PLAYMOBIL Junior Dump Truck (71685)', 'Playmobil Junior', 'Playmobil UK', 'https://www.playmobil.com/en-gb/junior:-dump-truck/71685.html', NULL, '£17.99 (marketplace list; confirm on Playmobil till)', 'in_stock', 'Age: 1 years and up / Junior 1-4 years', 'Junior dump truck with a tipping bed and stackable numbered stones for load, tip, stack and return play.', 'Best when the child wants a work trip — load, tip, stack, go back — with one clear figure. Still Junior only; do not substitute classic Playmobil dump trucks with under-3 warnings.', 'Clear go / work / return loop with chunky Junior parts.', 'Thinner public UK review scrape than DUPLO Construction; specialist exemption.', 'buy', true, 'Nice mid-price gift for vehicle lovers who already have a people set.', 'Lower duplication than Happyland bus.', NULL, 'specialist', ARRAY['https://www.playmobil.com/en-gb/junior:-dump-truck/71685.html']::text[], 'confirm_price_and_reviews'),
    ('cat_small_world_figures', 5, 5, 'visible', true, true, 'Best for rebuild vehicle jobs', 'LEGO DUPLO 3-in-1 Construction Vehicles (10475)', 'LEGO DUPLO', 'Amazon UK', 'https://www.amazon.co.uk/LEGO-10475-tbd-10475/dp/B01MTWBPPI', NULL, '£13.99 (John Lewis list observed; confirm Hamleys till)', 'in_stock', 'Ages 2+', 'Rebuild three different site vehicles from one DUPLO pack so the child can invent new go-and-work trips.', 'Kept in Top 5 as the evidence-backed workhorse when bus and Junior helper sets already feel covered. Strong Amazon UK ratings; slightly weaker on people/feelings than the ranks above.', 'Supports go / work / return with chunky 2+ bricks, though figures are thinner than Happyland or Junior heroes.', 'Amazon primary chosen because Hamleys page blocked bot availability checks — verify till price on click-through.', 'buy', true, 'Safe gift for a DUPLO house; less ideal as the only small-world set if they need people play.', 'Common DUPLO set — check the brick box first.', NULL, 'strong', ARRAY['https://www.hamleys.com/lego-duplo-town-3-in-1-construction-vehicles-toys-10475', 'https://www.amazon.co.uk/LEGO-10475-tbd-10475/dp/B01MTWBPPI']::text[], 'check_price'),
    ('cat_threading_beads', 1, 1, 'visible', true, false, 'Best for letters and lacing', 'Smart Snacks ABC Lacing Sweets', 'Learning Resources', 'Primary ICT', 'https://www.primaryict.co.uk/pr8561/smart-snacks-abc-lacing-sweets-learning-r-ler7204', NULL, '£27.38', 'in_stock', 'Ages 2-6 years', 'Twenty-six chunky 4.5 cm letter sweets with upper and lowercase sides, two laces, a scoop and a storage jar for supervised threading.', 'At nearly three, hands want a neater job than posting. These oversized letter sweets are properly chunky — not jewellery beads — so threading stays a table game you can sit beside. The stockist mark is Ages 2–6, which overlaps this band cleanly; keep sessions supervised and shorten cords when you pack away.', 'Large bead size and Ages 2–6 mark clear the 34–36m age gate; letter faces add a light copy-and-name layer without tiny craft pieces.', 'Some Amazon listings print generic under-36 choking boilerplate — we follow the Learning Resources Ages 2–6 mark and 4.5 cm piece size from the live UK stockist page.', 'buy', true, 'Strong gift if the child already notices letters; jar presentation wraps cleanly.', 'Skip if you already own oversized letter lacing sweets; do not double up with tiny alphabet jewellery kits.', 'Supervised play only. Keep laces short during use and store out of reach when finished.', 'strong', ARRAY['https://www.primaryict.co.uk/pr8561/smart-snacks-abc-lacing-sweets-learning-r-ler7204', 'https://www.amazon.co.uk/Learning-Resources-Snacks-Lacing-Sweets/dp/B0007KLHBE']::text[], 'none'),
    ('cat_threading_beads', 2, 2, 'visible', true, true, 'Best for storybook threading', 'Caterpillar Fruit Feast Set', 'Hape', 'Hape', 'https://global.hape.com/caterpillar-fruit-feast-set-e1072', NULL, 'about £15', 'in_stock', '18 months+', 'Two wooden caterpillar cords and thirteen chunky fruit pieces to thread, with leaf stoppers so fruit stays on the string.', 'This is threading with a job — feed the caterpillar — which suits a nearly-three who wants a finished line to show you. Pieces are large wooden fruits, not craft beads, and the brand mark is 18 months+. Sit together; cords still need supervision.', 'Narrative threading matches the busy-hands cluster without jumping to 3+ jewellery-size beads.', 'Amazon UK listing was out of stock at check; brand page remained buyable. Pair with The Very Hungry Caterpillar only if you already own it.', 'buy', true, 'Cute gift angle without feeling like a jewellery kit.', 'Different format from open bead crates — complements rather than duplicates.', 'Supervised play only. Brand age 18 months+. Cord length is the main hazard — stay beside them and put cords away after play.', 'strong', ARRAY['https://global.hape.com/caterpillar-fruit-feast-set-e1072', 'https://www.amazon.co.uk/dp/B0BB23Y1B7']::text[], 'check_stock'),
    ('cat_threading_beads', 3, 3, 'visible', true, true, 'Best for chunky first beads', 'Filacolor Lacing Beads', 'Djeco', 'Tickety-Boo Toys', 'https://www.tickety-boo-toys.co.uk/filacolor-lacing-beads-by-djeco.html', NULL, '£11.90', 'in_stock', '18 months+', 'Twenty-four chunky wooden stars, circles and squares with two fabric laces in a small tub — a first threading set from 18 months.', 'If you want proper wooden beads without a 3+ crate warning, Filacolor is the calm UK specialist option. Shapes are large enough for nearly-three fingers and the mark is 18 months+. Still sit together — fabric laces tangle fast.', 'True 18m+ chunky wooden threading that clears the band age gate where Melissa & Doug / Bigjigs 3+ sets fail.', 'Fewer mass-market Amazon ratings than Melissa & Doug; buy from a named UK Djeco stockist. Not a pattern-card set.', 'buy', true, 'Compact gift that still feels intentional.', 'Enough if you only need one small bead tub; skip if you already own oversized wooden stars/circles.', 'Supervised play only. 18 months+ mark. Keep fabric laces short in use and store away from younger siblings.', 'good', ARRAY['https://www.tickety-boo-toys.co.uk/filacolor-lacing-beads-by-djeco.html', 'https://daisydaisydirect.co.uk/play-time/djeco-filacolour-lacing-beads-dj06160.html']::text[], 'none'),
    ('cat_threading_beads', 4, 4, 'visible', true, true, 'Best for copying patterns', 'Beads & Pattern Card Set', 'Learning Resources', 'Primary ICT', 'https://www.primaryict.co.uk/pr8280/beads-pattern-card-set-set-of-130-pieces-ler0139', NULL, '£34.09', 'in_stock', 'Recommended for Ages: 3 - 7 years', 'One hundred and eight hardwood beads with twenty activity cards and two tipped laces so children can copy pictured colour and shape sequences.', 'This is the pattern-copying pick the Stage 2 card asks for. Cards turn lacing into “make it match”, which is the shift at nearly three. The stockist marks Ages 3–7 — fine at the top of this band, but sit beside a 34-month-old and keep laces short.', 'Only buyable UK listing in this run that pairs chunky hardwood beads with pattern cards for copy-shapes play.', 'Listing starts at 3 years — borderline for a just-turned-34-month child. Beads are smaller than ABC sweets; supervise closely.', 'buy', true, 'Gift-forward for a child who already enjoys sorting and matching.', 'Skip if you already own a pattern-card bead set.', 'Supervised play only. Ages 3–7 mark. Shorten laces in use; store cards and beads away from younger siblings.', 'good', ARRAY['https://www.primaryict.co.uk/pr8280/beads-pattern-card-set-set-of-130-pieces-ler0139']::text[], 'check_age_fit'),
    ('cat_threading_beads', 5, 5, 'visible', true, true, 'Best for safer cord ends', 'Edushape Sensory Baby Beads', 'Edushape', 'TTS', 'https://www.tts-group.co.uk/edushape-sensory-baby-beads-14pk/1053971.html', NULL, '£23.99', 'in_stock', '12 months+', 'Ten chunky 4.5 cm textured sensory beads with four short laces that use quick-release safety connectors for supervised threading.', 'If cord worry is the blocker, this is the set with short safety-release laces and properly large beads. It is marked from 12 months, so it overlaps 34–36m cleanly. Still supervised — texture invites mouthing.', 'Large beads plus safety-release short cords are the safety-forward answer when classic 3+ wooden crates fail the band gate.', 'Less pattern-copy depth than the pattern-card set; fewer beads than a wooden crate. Nursery-channel pricing.', 'buy', true, 'Practical gift for parents who are nervous about long cords.', 'Complements a wooden bead set rather than replacing pattern play.', 'Supervised play only. Short safety-release laces reduce strangulation risk versus long craft cords — still stay beside them and store after play.', 'good', ARRAY['https://www.tts-group.co.uk/edushape-sensory-baby-beads-14pk/1053971.html', 'https://halilit.co.uk/products/baby-beads']::text[], 'none'),
    ('cat_visual_routine_cards', 1, 1, 'visible', true, false, 'Best for whole-day routines', 'Visual Timetable for Children at Home', 'Create Visual Aids', 'Amazon UK (sold by Create Visual Aids)', 'https://www.amazon.co.uk/Create-Visual-Aids-communication-transition/dp/B093YJ5RL6', NULL, '£15.95 approx. (Amazon; confirm at checkout)', 'in_stock', 'Ages 2+ parent-setup preschool tool', 'Thirty-five durable home-routine picture cards with two A4 boards and Velcro. Displays up to ten steps of the day at once.', 'If fridge photos have not stuck, this is the grown-up version — rearrangeable home symbols for shoes, teeth, coat, bag. At nearly three, independence wants a visible plan, not a lecture. Try your own photos first; buy if DIY still fails after a fortnight.', 'Mainstream UK home timetable with rearrangeable cards matching whole-routine independence without school-only symbols.', 'Generic symbols, not your child’s room — photos may still beat this. Ten-card display limit. Amazon primary because brand site bot-blocks automated checks.', 'buy', false, 'Parent-buy utility; not a gift unless parents asked.', 'Try phone photos of your real routine first — skip if that already works.', 'Small cards or tokens — supervise around younger siblings; store spares out of reach.', 'strong', ARRAY['https://www.amazon.co.uk/Create-Visual-Aids-communication-transition/dp/B093YJ5RL6', 'https://www.createvisualaids.co.uk/products/visual-timetable-for-home-1']::text[], 'none'),
    ('cat_visual_routine_cards', 2, 2, 'visible', true, true, 'Best for morning battles', 'Children''s Daily Routine Board', 'Craftly', 'Craftly', 'https://www.craftly.co.uk/products/childrens-daily-routine-board', NULL, 'From £24.00 (A4/A3 options)', 'in_stock', 'Ages 2+ parent-setup preschool tool', 'Aluminium morning-and-evening routine board with golden-star progress. Child moves a star when each illustrated step is done.', 'Prettier than clinic boards — useful when mornings and bedtimes are the only war zones. Stars give a nearly-three a finished-job feeling fridge photos may lack. Try two photos on the bathroom door before spending.', 'Split AM/PM board with visible progress suits independence pride when whole-day charts feel like too much.', 'Only one on-page review; metal tokens need supervision around babies. Handmade lead time (Craftly ships Wed).', 'buy', false, 'Parent-buy utility; not a gift unless parents asked.', 'Try phone photos of your real routine first — skip if that already works.', 'Small cards or tokens — supervise around younger siblings; store spares out of reach.', 'good', ARRAY['https://www.craftly.co.uk/products/childrens-daily-routine-board']::text[], 'check_claim'),
    ('cat_visual_routine_cards', 3, 3, 'visible', true, true, 'Best for tricky transitions', 'Now, Next Then Visual Timetable', 'Craftly', 'Craftly', 'https://www.craftly.co.uk/products/now-and-next-visual-routine-board', NULL, 'From £11.00 (tokens sold separately)', 'in_stock', 'Ages 2+ parent-setup preschool tool', 'Handmade A5 aluminium Now-Next-Then board with zip folder. Tokens sold separately so you match your child’s real jobs.', 'When the whole day feels like too much, shrink the horizon: Now shoes, Next park. Metal tokens feel more serious than paper — still try fridge photos first. Buy the board plus only the tokens you will use.', 'Two- or three-step transition board matches sticky hand-offs better than a ten-step wall chart for many nearly-threes.', 'Tokens not included — budget for them. Five on-page reviews; specialist exemption.', 'buy', false, 'Parent-buy utility; not a gift unless parents asked.', 'Try phone photos of your real routine first — skip if that already works.', 'Small cards or tokens — supervise around younger siblings; store spares out of reach.', 'good', ARRAY['https://www.craftly.co.uk/products/now-and-next-visual-routine-board']::text[], 'check_claim'),
    ('cat_visual_routine_cards', 4, 4, 'visible', true, true, 'Best for portable routines', 'My Communication Book for Early Years Settings', 'Create Visual Aids', 'Amazon UK (sold by Create Visual Aids)', 'https://www.amazon.co.uk/Create-Visual-Aids-My-Communication-Book/dp/B0CJ5QXG8L', NULL, '£25.00 approx. (Amazon; confirm at checkout)', 'in_stock', 'Ages 2+ parent-setup preschool tool', 'Portable A5 book bundling Now/Next and other early-years visual inserts with thirty-four removable routine symbols.', 'Worth it when routines need to travel — childminder days, divorced-household handovers, or a kid who ignores wall charts in rooms they do not own. Heavier than a door strip; skip if one wall chart already works.', 'Consolidates transition and routine symbols into one carryable book for families whose schedule moves between rooms or carers.', 'Broader than pure routine cards; premium versus a single wall strip. Brand site bot-blocks agents — Amazon primary.', 'buy', false, 'Parent-buy utility; not a gift unless parents asked.', 'Try phone photos of your real routine first — skip if that already works.', 'Small cards or tokens — supervise around younger siblings; store spares out of reach.', 'strong', ARRAY['https://www.amazon.co.uk/Create-Visual-Aids-My-Communication-Book/dp/B0CJ5QXG8L']::text[], 'confirm_reviews_on_human_click'),
    ('cat_visual_routine_cards', 5, 5, 'visible', true, true, 'Best for custom strips', 'Bespoke Visual Timetable', 'Craftly', 'Craftly', 'https://www.craftly.co.uk/products/visual-timetables-to-do-list', NULL, 'From £10.00 (tokens sold separately)', 'in_stock', 'Ages 2+ parent-setup preschool tool', 'Handmade metal visual timetable strip with zip folder. Buy only the routine tokens you need for your child’s real jobs.', 'Pick this when a full 35-card kit is overkill — three or four real jobs, printed on metal so it survives the bathroom. Same photos-first rule: blu-tack trial before checkout.', 'Configurable strip length for families who want fewer, bespoke steps without a whole-day foamex board.', 'Tokens cost extra. Eleven reviews — meets numeric bar but thin versus Create Visual Aids volume.', 'buy', false, 'Parent-buy utility; not a gift unless parents asked.', 'Try phone photos of your real routine first — skip if that already works.', 'Small cards or tokens — supervise around younger siblings; store spares out of reach.', 'good', ARRAY['https://www.craftly.co.uk/products/visual-timetables-to-do-list']::text[], 'check_claim')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
)
INSERT INTO public.pl_stage3_picks (
  age_band_id,
  category_type_id,
  source_category_entity_id,
  pick_rank,
  longlist_rank,
  status,
  is_visible,
  is_locked,
  best_for_tag,
  product_name,
  brand,
  retailer,
  product_url,
  image_url,
  price_text,
  stock_status,
  age_mark_on_listing,
  product_description,
  ember_verdict,
  why_it_fits,
  caveats,
  buy_borrow_hold_off,
  gift_suitable,
  gift_note,
  ownership_note,
  safety_notes,
  evidence_tier,
  evidence_sources,
  founder_qa_flag,
  research_payload
)
SELECT
  '34-36m',
  ct.id,
  r.source_category_entity_id,
  r.pick_rank,
  r.longlist_rank,
  r.status,
  r.is_visible,
  r.is_locked,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.image_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.product_description,
  r.ember_verdict,
  r.why_it_fits,
  r.caveats,
  r.buy_borrow_hold_off,
  r.gift_suitable,
  r.gift_note,
  r.ownership_note,
  r.safety_notes,
  r.evidence_tier,
  r.evidence_sources,
  r.founder_qa_flag,
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-22T09:08:04.175Z',
    'research_schema_version', 'ember_picks_research_v2',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM stage3_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '34-36m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

WITH backup_rows AS (
  SELECT *
  FROM (VALUES
    ('cat_balance_stepping_stones', 6, 'National Geographic Stepping Stones 6-pack with spinner', 'National Geographic', 'Best for spinner games', 'https://www.amazon.co.uk/NATIONAL-GEOGRAPHIC-Durable-Non-Slip-Stepping/dp/B0C95HPFHM', 'Amazon UK', '£22.99', 'in_stock', 'Ages 3+ years', 'strong', 'buy', true, '3+ age mark — not Top 5 for this band.'),
