)
SELECT
  '34-36m',
  ct.id,
  r.source_category_entity_id,
  r.longlist_rank,
  r.longlist_rank,
  'backup',
  false,
  true,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.caveat_short,
  r.buy_borrow_hold_off,
  -- All-NULL VALUES columns are inferred as text; cast for the boolean target column.
  r.gift_suitable::boolean,
  r.evidence_tier,
  'backup_not_card_ready',
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-22T09:08:04.175Z',
    'status', 'dormant_backup',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM backup_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '34-36m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

DO $$
DECLARE
  v_visible_count INTEGER;
  v_backup_count INTEGER;
BEGIN
  SELECT COUNT(*) INTO v_visible_count
  FROM public.pl_stage3_picks s
  JOIN public.pl_category_types ct ON ct.id = s.category_type_id
  WHERE s.age_band_id = '34-36m'
    AND ct.slug IN ('cat_balance_stepping_stones', 'cat_feelings_faces_books', 'cat_jigsaw_puzzles', 'cat_picture_story_books', 'cat_small_world_figures', 'cat_threading_beads', 'cat_visual_routine_cards')
    AND s.status = 'visible'
    AND s.is_visible = true;

  IF v_visible_count <> 35 THEN
    RAISE EXCEPTION 'Expected 35 visible Stage 3 picks for 34-36m, got %', v_visible_count;
  END IF;

  SELECT COUNT(*) INTO v_backup_count
  FROM public.pl_stage3_picks s
  JOIN public.pl_category_types ct ON ct.id = s.category_type_id
  WHERE s.age_band_id = '34-36m'
    AND ct.slug IN ('cat_balance_stepping_stones', 'cat_feelings_faces_books', 'cat_jigsaw_puzzles', 'cat_picture_story_books', 'cat_small_world_figures', 'cat_threading_beads', 'cat_visual_routine_cards')
    AND s.status = 'backup'
    AND s.is_visible = false;

  IF v_backup_count <> 69 THEN
    RAISE EXCEPTION 'Expected 69 backup Stage 3 picks for 34-36m, got %', v_backup_count;
  END IF;
END $$;

COMMIT;
